  1→import { useState } from 'react';
  2→import { useForm, useFieldArray } from 'react-hook-form';
  3→import { zodResolver } from '@hookform/resolvers/zod';
  4→import { cn } from '@/lib/utils';
  5→import { roomSchema, type RoomFormValues } from '@/lib/schemas';
  6→import { useBookingStore } from '@/Stores/useBookingStore';
  7→import { calculateNights, calculatePrice } from '@/lib/utils/calculatePrice';
  8→import { formatCurrency } from '@/lib/utils/formatCurrency';
  9→import { Button } from '@/Components/ui/button';
 10→import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/Components/ui/card';
 11→import { Label } from '@/Components/ui/label';
 12→import { Badge } from '@/Components/ui/badge';
 13→import { Separator } from '@/Components/ui/separator';
 14→import { MinusIcon, PlusIcon, UsersIcon, ChevronDownIcon, ChevronUpIcon } from 'lucide-react';
 15→import { ImageCarousel } from './ImageCarousel';
 16→import type { PropertyData, Unit } from '@/types/property';
 17→
 18→interface RoomStepProps {
 19→  propertyData: PropertyData;
 20→}
 21→
 22→export function RoomStep({ propertyData }: RoomStepProps) {
 23→  const { checkIn, checkOut, rooms: storedRooms, setRooms, nextStep, prevStep } = useBookingStore();
 24→  const { units, property } = propertyData;
 25→  const nights = checkIn && checkOut ? calculateNights(checkIn, checkOut) : 0;
 26→
 27→  // Track which cards have the per-room guest section expanded
 28→  const [expandedGuests, setExpandedGuests] = useState<Record<number, boolean>>({});
 29→
 30→  const defaultRooms = units.map((unit) => {
 31→    const existing = storedRooms.find((r) => r.unitId === unit.id);
 32→    if (existing) {
 33→      return {
 34→        unitId: unit.id,
 35→        quantity: existing.quantity,
 36→        guests: existing.guests,
 37→        guestsPerRoom: existing.guestsPerRoom ?? Array(existing.quantity).fill(
 38→          Math.max(1, Math.floor(existing.guests / existing.quantity))
 39→        ),
 40→      };
 41→    }
 42→    return { unitId: unit.id, quantity: 0, guests: 0, guestsPerRoom: [] as number[] };
 43→  });
 44→
 45→  const {
 46→    control,
 47→    handleSubmit,
 48→    watch,
 49→    setValue,
 50→    formState: { errors },
 51→  } = useForm<RoomFormValues>({
 52→    resolver: zodResolver(roomSchema),
 53→    defaultValues: { rooms: defaultRooms },
 54→  });
 55→
 56→  const { fields } = useFieldArray({ control, name: 'rooms' });
 57→  const watchedRooms = watch('rooms');
 58→
 59→  const breakdown = calculatePrice(watchedRooms, units, nights, property.tax_rate);
 60→
 61→  const onSubmit = (data: RoomFormValues) => {
 62→    const filtered = data.rooms
 63→      .filter((r) => r.quantity > 0)
 64→      .map((r) => ({
 65→        ...r,
 66→        guests: r.guestsPerRoom?.reduce((sum, g) => sum + g, 0) ?? r.guests,
 67→      }));
 68→    setRooms(filtered);
 69→    nextStep();
 70→  };
 71→
 72→  const handleQuantityChange = (index: number, delta: number, unit: Unit) => {
 73→    const current = watchedRooms[index].quantity;
 74→    const newQty = Math.max(0, Math.min(current + delta, unit.available_count));
 75→    const currentPerRoom = watchedRooms[index].guestsPerRoom ?? [];
 76→
 77→    setValue(`rooms.${index}.quantity`, newQty, { shouldValidate: true });
 78→
 79→    if (newQty === 0) {
 80→      setValue(`rooms.${index}.guests`, 0);
 81→      setValue(`rooms.${index}.guestsPerRoom`, []);
 82→      setExpandedGuests((prev) => ({ ...prev, [index]: false }));
 83→    } else if (newQty > current) {
 84→      const base = current === 0 ? [] : currentPerRoom;
 85→      const newPerRoom = [...base, ...Array(newQty - current).fill(1)];
 86→      setValue(`rooms.${index}.guestsPerRoom`, newPerRoom);
 87→      setValue(`rooms.${index}.guests`, newPerRoom.reduce((s, g) => s + g, 0));
 88→    } else if (newQty < current) {
 89→      const newPerRoom = currentPerRoom.slice(0, newQty);
 90→      setValue(`rooms.${index}.guestsPerRoom`, newPerRoom);
 91→      setValue(`rooms.${index}.guests`, newPerRoom.reduce((s, g) => s + g, 0));
 92→    }
 93→  };
 94→
 95→  const handlePerRoomGuestChange = (roomIndex: number, guestIndex: number, delta: number, unit: Unit) => {
 96→    const perRoom = [...(watchedRooms[roomIndex].guestsPerRoom ?? [])];
 97→    const current = perRoom[guestIndex] ?? 1;
 98→    perRoom[guestIndex] = Math.max(1, Math.min(current + delta, unit.max_guests));
 99→    setValue(`rooms.${roomIndex}.guestsPerRoom`, perRoom);
100→    setValue(`rooms.${roomIndex}.guests`, perRoom.reduce((s, g) => s + g, 0));
101→  };
102→
103→  const toggleExpanded = (index: number) => {
104→    setExpandedGuests((prev) => ({ ...prev, [index]: !prev[index] }));
105→  };
106→
107→  return (
108→    <form onSubmit={handleSubmit(onSubmit)} className={cn('space-y-6')}>
109→      <h2 className={cn('text-xl font-semibold')}>Select your rooms</h2>
110→
111→      {errors.rooms?.root && (
112→        <p className={cn('text-sm text-destructive')} role="alert">
113→          {errors.rooms.root.message}
114→        </p>
115→      )}
116→
117→      <div className={cn('grid grid-cols-1 gap-4 md:grid-cols-2')}>
118→        {fields.map((field, index) => {
119→          const unit = units.find((u) => u.id === field.unitId);
120→          if (!unit) return null;
121→
122→          const qty = watchedRooms[index]?.quantity ?? 0;
123→          const perRoom = watchedRooms[index]?.guestsPerRoom ?? [];
124→          const totalGuests = perRoom.reduce((s, g) => s + g, 0);
125→          const isExpanded = expandedGuests[index] ?? false;
126→
127→          // Calculate line total for this room
128→          const lineTotal =
129→            unit.pricing_model === 'per_unit'
130→              ? unit.price * nights * qty
131→              : unit.price * totalGuests * nights;
132→
133→          return (
134→            <Card key={field.id} className={cn('pt-0')}>
135→              <ImageCarousel
136→                images={unit.pictures}
137→                alt={unit.name}
138→                className={cn('h-40')}
139→              />
140→              <CardHeader>
141→                <div className={cn('flex items-start justify-between')}>
142→                  <CardTitle>{unit.name}</CardTitle>
143→                  <Badge variant="secondary">
144→                    {unit.available_count} available
145→                  </Badge>
146→                </div>
147→                <CardDescription>
148→                  {formatCurrency(unit.price)}{' '}
149→                  {unit.pricing_model === 'per_unit'
150→                    ? 'per room / night'
151→                    : 'per person / night'}
152→                  {' - '}Up to {unit.max_guests}{' '}
153→                  {unit.max_guests === 1 ? 'guest' : 'guests'}
154→                </CardDescription>
155→              </CardHeader>
156→              <CardContent className={cn('space-y-4')}>
157→                {/* Quantity selector */}
158→                <div className={cn('space-y-2')}>
159→                  <Label>Rooms</Label>
160→                  <div className={cn('flex items-center gap-3')}>
161→                    <Button
162→                      type="button"
163→                      variant="outline"
164→                      size="icon"
165→                      className={cn('min-h-11 min-w-11')}
166→                      onClick={() => handleQuantityChange(index, -1, unit)}
167→                      disabled={qty === 0}
168→                      aria-label={`Decrease ${unit.name} quantity`}
169→                    >
170→                      <MinusIcon className={cn('h-4 w-4')} />
171→                    </Button>
172→                    <span
173→                      className={cn('w-8 text-center text-lg font-medium')}
174→                      aria-live="polite"
175→                      aria-label={`${qty} ${unit.name} rooms selected`}
176→                    >
177→                      {qty}
178→                    </span>
179→                    <Button
180→                      type="button"
181→                      variant="outline"
182→                      size="icon"
183→                      className={cn('min-h-11 min-w-11')}
184→                      onClick={() => handleQuantityChange(index, 1, unit)}
185→                      disabled={qty >= unit.available_count}
186→                      aria-label={`Increase ${unit.name} quantity`}
187→                    >
188→                      <PlusIcon className={cn('h-4 w-4')} />
189→                    </Button>
190→                  </div>
191→                </div>
192→
193→                {/* Guest section - shown when quantity > 0 */}
194→                {qty > 0 && (
195→                  <div className={cn('space-y-3')}>
196→                    {/* Summary row with customize toggle */}
197→                    <button
198→                      type="button"
199→                      onClick={() => qty > 1 ? toggleExpanded(index) : undefined}
200→                      className={cn(
201→                        'flex w-full items-center justify-between rounded-md bg-muted px-3 py-2 text-sm',
202→                        qty > 1 && 'cursor-pointer hover:bg-muted/80'
203→                      )}
204→                    >
205→                      <span className={cn('flex items-center gap-1.5')}>
206→                        <UsersIcon className={cn('h-4 w-4 text-muted-foreground')} />
207→                        <span className={cn('font-medium')}>
208→                          {totalGuests} {totalGuests === 1 ? 'guest' : 'guests'} total
209→                        </span>
210→                      </span>
211→                      {qty > 1 && (
212→                        <span className={cn('flex items-center gap-1 text-xs text-muted-foreground')}>
213→                          Customize
214→                          {isExpanded ? (
215→                            <ChevronUpIcon className={cn('h-3.5 w-3.5')} />
216→                          ) : (
217→                            <ChevronDownIcon className={cn('h-3.5 w-3.5')} />
218→                          )}
219→                        </span>
220→                      )}
221→                    </button>
222→
223→                    {/* Single room - inline stepper (no expand needed) */}
224→                    {qty === 1 && (
225→                      <div className={cn('flex items-center gap-3')}>
226→                        <Label className={cn('text-sm text-muted-foreground')}>Guests</Label>
227→                        <Button
228→                          type="button"
229→                          variant="outline"
230→                          size="icon"
231→                          className={cn('h-8 w-8')}
232→                          onClick={() => handlePerRoomGuestChange(index, 0, -1, unit)}
233→                          disabled={(perRoom[0] ?? 1) <= 1}
234→                          aria-label="Decrease guests"
235→                        >
236→                          <MinusIcon className={cn('h-3 w-3')} />
237→                        </Button>
238→                        <span className={cn('w-6 text-center text-sm font-medium')}>
239→                          {perRoom[0] ?? 1}
240→                        </span>
241→                        <Button
242→                          type="button"
243→                          variant="outline"
244→                          size="icon"
245→                          className={cn('h-8 w-8')}
246→                          onClick={() => handlePerRoomGuestChange(index, 0, 1, unit)}
247→                          disabled={(perRoom[0] ?? 1) >= unit.max_guests}
248→                          aria-label="Increase guests"
249→                        >
250→                          <PlusIcon className={cn('h-3 w-3')} />
251→                        </Button>
252→                      </div>
253→                    )}
254→
255→                    {/* Multiple rooms - expandable per-room controls */}
256→                    {qty > 1 && isExpanded && (
257→                      <div className={cn('space-y-2 rounded-md border p-3')}>
258→                        {perRoom.map((guestCount, gi) => (
259→                          <div key={gi} className={cn('flex items-center justify-between')}>
260→                            <span className={cn('text-sm text-muted-foreground')}>
261→                              Room {gi + 1}
262→                            </span>
263→                            <div className={cn('flex items-center gap-2')}>
264→                              <Button
265→                                type="button"
266→                                variant="outline"
267→                                size="icon"
268→                                className={cn('h-7 w-7')}
269→                                onClick={() => handlePerRoomGuestChange(index, gi, -1, unit)}
270→                                disabled={guestCount <= 1}
271→                                aria-label={`Decrease guests for room ${gi + 1}`}
272→                              >
273→                                <MinusIcon className={cn('h-3 w-3')} />
274→                              </Button>
275→                              <span className={cn('w-6 text-center text-sm font-medium')}>
276→                                {guestCount}
277→                              </span>
278→                              <Button
279→                                type="button"
280→                                variant="outline"
281→                                size="icon"
282→                                className={cn('h-7 w-7')}
283→                                onClick={() => handlePerRoomGuestChange(index, gi, 1, unit)}
284→                                disabled={guestCount >= unit.max_guests}
285→                                aria-label={`Increase guests for room ${gi + 1}`}
286→                              >
287→                                <PlusIcon className={cn('h-3 w-3')} />
288→                              </Button>
289→                              <span className={cn('text-xs text-muted-foreground')}>
290→                                {guestCount === 1 ? 'guest' : 'guests'}
291→                              </span>
292→                            </div>
293→                          </div>
294→                        ))}
295→                      </div>
296→                    )}
297→                  </div>
298→                )}
299→
300→                {/* Line total */}
301→                {qty > 0 && (
302→                  <div
303→                    className={cn(
304→                      'rounded-md bg-muted px-3 py-2 text-sm font-medium'
305→                    )}
306→                  >
307→                    {formatCurrency(lineTotal)}
308→                    <span className={cn('text-muted-foreground')}>
309→                      {' '}
310→                      for {nights} {nights === 1 ? 'night' : 'nights'}
311→                    </span>
312→                  </div>
313→                )}
314→              </CardContent>
315→            </Card>
316→          );
317→        })}
318→      </div>
319→
320→      {/* Running total */}
321→      {breakdown.subtotal > 0 && (
322→        <>
323→          <Separator />
324→          <div className={cn('space-y-1 text-right')}>
325→            <p className={cn('text-sm text-muted-foreground')}>
326→              Subtotal: {formatCurrency(breakdown.subtotal)}
327→            </p>
328→            <p className={cn('text-sm text-muted-foreground')}>
329→              VAT ({(breakdown.taxRate * 100).toFixed(0)}%):{' '}
330→              {formatCurrency(breakdown.taxAmount)}
331→            </p>
332→            <p className={cn('text-lg font-semibold')}>
333→              Total: {formatCurrency(breakdown.total)}
334→            </p>
335→          </div>
336→        </>
337→      )}
338→
339→      <div className={cn('flex justify-between')}>
340→        <Button type="button" variant="outline" size="lg" onClick={prevStep}>
341→          Back
342→        </Button>
343→        <Button type="submit" size="lg">
344→          Next: Review Booking
345→        </Button>
346→      </div>
347→    </form>
348→  );
349→}
