 24→
 25→const MAX_SPECIAL_REQUESTS_LENGTH = 500;
 26→
 27→interface SummaryStepProps {
 28→  propertyData: PropertyData;
 29→  auth: { user: User | null };
 30→}
 31→
 32→export function SummaryStep({ propertyData, auth }: SummaryStepProps) {
 33→  const {
 34→    checkIn,
 35→    checkOut,
 36→    rooms,
 37→    specialRequests,
 38→    setSpecialRequests,
 39→    setBookingId,
 40→    prevStep,
 41→    goToStep,
 42→  } = useBookingStore();
