 1→<?php
 2→
 3→namespace App\Services;
 4→
 5→use Carbon\Carbon;
 6→
 7→class PricingService
 8→{
 9→    public function __construct(
10→        private PropertyService $propertyService,
11→    ) {}
12→
13→    /**
14→     * Calculate server-authoritative pricing from validated booking data.
15→     *
16→     * Returns a breakdown with enriched rooms, subtotal, tax, and total.
17→     */
18→    public function calculate(array $validatedData): array
19→    {
20→        $checkIn = Carbon::parse($validatedData['check_in']);
21→        $checkOut = Carbon::parse($validatedData['check_out']);
22→        $nights = $checkIn->diffInDays($checkOut);
23→        $units = $this->propertyService->getUnitsIndexed();
24→        $property = $this->propertyService->get();
25→        $taxRate = $property['property']['tax_rate'];
26→
27→        $enrichedRooms = [];
28→        $subtotal = 0;
29→
30→        foreach ($validatedData['rooms'] as $room) {
31→            $unit = $units[$room['unit_id']];
32→            $quantity = $room['quantity'];
33→            $guests = $room['guests'];
34→
35→            if ($unit['pricing_model'] === 'per_unit') {
36→                $roomSubtotal = $unit['price'] * $nights * $quantity;
37→            } else {
38→                // per_person: price * guests * nights * quantity
39→                $roomSubtotal = $unit['price'] * $guests * $nights * $quantity;
40→            }
41→
42→            $enrichedRooms[] = [
43→                'unit_id' => $unit['id'],
44→                'unit_name' => $unit['name'],
45→                'pricing_model' => $unit['pricing_model'],
46→                'unit_price' => $unit['price'],
47→                'quantity' => $quantity,
48→                'guests' => $guests,
49→                'subtotal' => round($roomSubtotal, 2),
50→            ];
51→
52→            $subtotal += $roomSubtotal;
53→        }
54→
55→        $subtotal = round($subtotal, 2);
56→        $taxAmount = round($subtotal * $taxRate, 2);
57→        $totalPrice = round($subtotal + $taxAmount, 2);
58→
59→        return [
60→            'nights' => $nights,
61→            'rooms' => $enrichedRooms,
62→            'subtotal' => $subtotal,
63→            'tax_rate' => $taxRate,
64→            'tax_amount' => $taxAmount,
65→            'total_price' => $totalPrice,
66→        ];
67→    }
68→
69→    public function verifyClientTotal(float $clientTotal, float $serverTotal, float $tolerance = 0.01): bool
70→    {
71→        return abs($clientTotal - $serverTotal) <= $tolerance;
72→    }
73→}
