 1→<?php
 2→
 3→namespace App\Http\Requests;
 4→
 5→use App\Services\PropertyService;
 6→use Illuminate\Foundation\Http\FormRequest;
 7→
 8→class StoreBookingRequest extends FormRequest
 9→{
10→    public function authorize(): bool
11→    {
12→        return true;
13→    }
14→
15→    public function rules(): array
16→    {
17→        return [
18→            'check_in' => ['required', 'date', 'after_or_equal:today'],
19→            'check_out' => ['required', 'date', 'after:check_in'],
20→            'rooms' => ['required', 'array', 'min:1'],
21→            'rooms.*.unit_id' => ['required', 'integer'],
22→            'rooms.*.quantity' => ['required', 'integer', 'min:1'],
23→            'rooms.*.guests' => ['required', 'integer', 'min:1'],
24→            'special_requests' => ['nullable', 'string', 'max:500'],
25→            'submitted_total' => ['required', 'numeric', 'min:0'],
26→        ];
27→    }
28→
29→    /**
30→     * Custom validation: verify units exist, quantities don't exceed availability,
31→     * and guest counts respect max_guests per unit.
32→     */
33→    public function after(): array
34→    {
35→        return [
36→            function ($validator) {
37→                $propertyService = app(PropertyService::class);
38→                $units = $propertyService->getUnitsIndexed();
39→                $rooms = $this->input('rooms', []);
40→
41→                foreach ($rooms as $index => $room) {
42→                    $unitId = $room['unit_id'] ?? null;
43→
44→                    if ($unitId === null) {
45→                        continue;
46→                    }
47→
48→                    $unit = $units[$unitId] ?? null;
49→
50→                    if (!$unit) {
51→                        $validator->errors()->add(
52→                            "rooms.{$index}.unit_id",
53→                            "The selected room type does not exist."
54→                        );
55→                        continue;
56→                    }
57→
58→                    $quantity = $room['quantity'] ?? 0;
59→                    if ($quantity > $unit['available_count']) {
60→                        $validator->errors()->add(
61→                            "rooms.{$index}.quantity",
62→                            "Only {$unit['available_count']} {$unit['name']} room(s) available."
63→                        );
64→                    }
65→
66→                    $guests = $room['guests'] ?? 0;
67→                    $maxGuests = $unit['max_guests'] * $quantity;
68→                    if ($guests > $maxGuests) {
69→                        $validator->errors()->add(
70→                            "rooms.{$index}.guests",
71→                            "Maximum {$maxGuests} guest(s) allowed for {$quantity} {$unit['name']} room(s)."
72→                        );
73→                    }
74→                }
75→            },
76→        ];
77→    }
78→
79→    public function messages(): array
80→    {
81→        return [
82→            'check_in.after_or_equal' => 'Check-in date must be today or later.',
83→            'check_out.after' => 'Check-out date must be after the check-in date.',
84→            'rooms.required' => 'Please select at least one room.',
85→            'rooms.min' => 'Please select at least one room.',
86→            'rooms.*.quantity.min' => 'Room quantity must be at least 1.',
87→            'rooms.*.guests.min' => 'Guest count must be at least 1.',
88→            'special_requests.max' => 'Special requests must be 500 characters or fewer.',
89→        ];
90→    }
91→}
