 3→namespace App\Jobs;
 4→
 5→use App\Models\Booking;
 6→use App\Services\ChannelManagerService;
 7→use Illuminate\Bus\Queueable;
 8→use Illuminate\Contracts\Queue\ShouldQueue;
 9→use Illuminate\Foundation\Bus\Dispatchable;
10→use Illuminate\Queue\InteractsWithQueue;
11→use Illuminate\Queue\SerializesModels;
12→use Illuminate\Support\Facades\Log;
13→use Illuminate\Support\Str;
14→use Throwable;
15→
16→class ProcessBookingJob implements ShouldQueue
17→{
18→    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;
19→
20→    public int $tries = 3;
21→
22→    /** @var array<int, int> */
23→    public array $backoff = [5, 15, 45];
24→
25→    public function __construct(
26→        public Booking $booking,
27→    ) {}
28→
29→    public function handle(ChannelManagerService $channelManager): void
30→    {
31→        $this->booking->update([
32→            'status' => 'processing',
33→            'attempts' => $this->booking->attempts + 1,
34→        ]);
35→
36→        $bookingData = [
37→            'reservation_id' => 'BK-' . strtoupper(Str::random(8)),
38→            'status' => 'new',
39→            'property_id' => $this->booking->property_id,
40→            'check_in' => $this->booking->check_in->toDateString(),
41→            'check_out' => $this->booking->check_out->toDateString(),
42→            'nights' => $this->booking->nights,
43→            'currency' => $this->booking->currency,
44→            'rooms' => $this->booking->rooms,
45→            'subtotal' => $this->booking->subtotal,
46→            'tax_rate' => $this->booking->tax_rate,
47→            'tax_amount' => $this->booking->tax_amount,
48→            'total_price' => $this->booking->total_price,
49→            'customer' => [
50→                'name' => $this->booking->user->name,
51→                'email' => $this->booking->user->email,
52→            ],
53→            'special_requests' => $this->booking->special_requests,
54→        ];
55→
56→        $result = $channelManager->book($bookingData);
57→
58→        $this->booking->update([
59→            'status' => 'confirmed',
60→            'external_confirmation_id' => $result['external_confirmation_id'],
61→        ]);
62→    }
63→
64→    public function failed(Throwable $exception): void
65→    {
66→        Log::error('Booking processing failed', [
67→            'booking_id' => $this->booking->id,
68→            'error' => $exception->getMessage(),
69→        ]);
70→
71→        $this->booking->update([
72→            'status' => 'failed',
73→        ]);
74→    }
75→}
