16→{
17→    public function __construct(
18→        private PricingService $pricingService,
19→        private PropertyService $propertyService,
20→    ) {}
21→
22→    public function store(StoreBookingRequest $request): JsonResponse|\Symfony\Component\HttpFoundation\Response
23→    {
24→        $validated = $request->validated();
25→        $property = $this->propertyService->get();
26→        $pricing = $this->pricingService->calculate($validated);
27→
28→        if (!$this->pricingService->verifyClientTotal($validated['submitted_total'], $pricing['total_price'])) {
29→            return response()->json([
30→                'message' => 'Price mismatch detected. Please review the updated pricing and try again.',
31→                'server_total' => $pricing['total_price'],
32→            ], 422);
33→        }
34→
35→        $booking = Booking::create([
36→            'user_id' => $request->user()->id,
37→            'property_id' => $property['property']['id'],
38→            'check_in' => $validated['check_in'],
39→            'check_out' => $validated['check_out'],
40→            'nights' => $pricing['nights'],
41→            'currency' => $property['property']['currency'],
42→            'rooms' => $pricing['rooms'],
43→            'subtotal' => $pricing['subtotal'],
44→            'tax_rate' => $pricing['tax_rate'],
45→            'tax_amount' => $pricing['tax_amount'],
46→            'total_price' => $pricing['total_price'],
47→            'special_requests' => $validated['special_requests'] ?? null,
48→            'status' => 'pending',
49→        ]);
50→
51→        ProcessBookingJob::dispatch($booking);
52→
53→        if ($request->wantsJson()) {
54→            return response()->json([
55→                'booking_id' => $booking->id,
